from math import gcd
from itertools import product


class Solution:
    def countCoprime(self, mat):
        MOD = 10**9 + 7
        total = 0
        for combo in product(*mat):
            g = 0
            for v in combo:
                g = gcd(g, v)
            if g == 1:
                total += 1
        return total % MOD

