from math import gcd


class Solution:
    def countCoprime(self, mat):
        MOD = 10**9 + 7
        dp = {0: 1}
        for row in mat:
            nxt = {}
            for g, cnt in dp.items():
                for v in row:
                    ng = gcd(g, v)
                    nxt[ng] = (nxt.get(ng, 0) + cnt) % MOD
            dp = nxt
        return dp.get(1, 0) % MOD

