var countCoprime = function(mat) {
    const MOD = 1000000007n;
    const gcd = (a, b) => { while (b) { [a, b] = [b, a % b]; } return a; };
    let dp = new Map([[0, 1n]]);
    for (const row of mat) {
        const nxt = new Map();
        for (const [g, cnt] of dp) {
            for (const v of row) {
                const ng = gcd(g, v);
                nxt.set(ng, ((nxt.get(ng) || 0n) + cnt) % MOD);
            }
        }
        dp = nxt;
    }
    return Number(dp.get(1) || 0n);
};
